from flask import Flask, session, redirect, url_for, request

app = Flask(__name__)
# Flask oturumları için SECRET_KEY zorunludur.
# Bu anahtarı güçlü ve gizli bir değerle değiştirin.
# Üretim ortamında kesinlikle sabit kodlanmamalı, çevre değişkenlerinden alınmalıdır.
app.secret_key = 'super_secret_key_buraya_gelecek' 

@app.route('/')
def index():
    if 'username' in session:
        username = session['username']
        return f'''
            <h1>Merhaba, {username}!</h1>
            <p><a href="/logout">Oturumu Kapat</a></p>
            <p><a href="/set_username_form">Kullanıcı Adı Belirle/Değiştir</a></p>
            <p>Mevcut oturum değeri: {session.get('my_data', 'Yok')}</p>
            <p><a href="/set_data">Ek Oturum Verisi Ayarla</a></p>
        '''
    return '''
        <h1>Merhaba, Misafir!</h1>
        <p><a href="/set_username_form">Kullanıcı Adı Belirle</a></p>
    '''

@app.route('/set_username_form')
def set_username_form():
    return '''
        <h1>Kullanıcı Adı Ayarla</h1>
        <form action="/set_username" method="post">
            <label for="username">Kullanıcı Adı:</label><br>
            <input type="text" id="username" name="username" required><br><br>
            <input type="submit" value="Kullanıcı Adını Ayarla">
        </form>
        <p><a href="/">Ana Sayfa</a></p>
    '''

@app.route('/set_username', methods=['POST'])
def set_username():
    if request.method == 'POST':
        username = request.form['username']
        session['username'] = username
        return redirect(url_for('index'))
    return redirect(url_for('index'))

@app.route('/set_data')
def set_data():
    session['my_data'] = 'Bu, oturuma eklenmiş özel bir veri!'
    return redirect(url_for('index'))

@app.route('/logout')
def logout():
    # Oturumdaki belirli bir anahtarı kaldırmak için .pop() kullanın.
    session.pop('username', None) 
    # Tüm oturumu temizlemek için session.clear() kullanın (dikkatli kullanın).
    # session.clear()
    return redirect(url_for('index'))

if __name__ == '__main__':
    app.run(debug=True)
